// Pull both `forall|p|` ensures into the proof context so their triggers
// line up under z3 (the schema scaffolding alone leaves them disjoint).
assert(forall|p: PagePtr|
    post1_self_.page_is_mapped(p) && p != target_ptr ==>
        post1_self_.page_mappings(p) =~= pre_self_.page_mappings(p)
        && post1_self_.page_io_mappings(p) =~= pre_self_.page_io_mappings(p));
assert(forall|p: PagePtr|
    post2_self_.page_is_mapped(p) && p != target_ptr ==>
        post2_self_.page_mappings(p) =~= pre_self_.page_mappings(p)
        && post2_self_.page_io_mappings(p) =~= pre_self_.page_io_mappings(p));

// allocated_pages_*: each post is `=~=` pre, so post1 `=~=` post2.
assert(post1_self_.allocated_pages_4k() =~= post2_self_.allocated_pages_4k());
assert(post1_self_.allocated_pages_2m() =~= post2_self_.allocated_pages_2m());
assert(post1_self_.allocated_pages_1g() =~= post2_self_.allocated_pages_1g());

// page_mappings / page_io_mappings at target_ptr: both forced to the
// same pre-derived value, so they agree pointwise on the affected page.
assert(post1_self_.page_mappings(target_ptr)
    =~= pre_self_.page_mappings(target_ptr).remove((pcid, va)));
assert(post2_self_.page_mappings(target_ptr)
    =~= pre_self_.page_mappings(target_ptr).remove((pcid, va)));
assert(post1_self_.page_mappings(target_ptr) =~= post2_self_.page_mappings(target_ptr));
assert(post1_self_.page_io_mappings(target_ptr) =~= pre_self_.page_io_mappings(target_ptr));
assert(post2_self_.page_io_mappings(target_ptr) =~= pre_self_.page_io_mappings(target_ptr));
assert(post1_self_.page_io_mappings(target_ptr) =~= post2_self_.page_io_mappings(target_ptr));

// container_map_*: each post equals the same pre-derived expression,
// so the two posts agree on every container-map view.
assert(post1_self_.container_map_2m@ =~= post2_self_.container_map_2m@);
assert(post1_self_.container_map_1g@ =~= post2_self_.container_map_1g@);
assert(post1_self_.container_map_4k@
    =~= pre_self_.container_map_4k@.insert(
        pre_self_.page_array@[page_ptr2page_index(target_ptr) as int]
            .owning_container.unwrap(),
        pre_self_.container_map_4k@[
            pre_self_.page_array@[page_ptr2page_index(target_ptr) as int]
                .owning_container.unwrap()
        ].remove(target_ptr),
    ));
assert(post2_self_.container_map_4k@
    =~= pre_self_.container_map_4k@.insert(
        pre_self_.page_array@[page_ptr2page_index(target_ptr) as int]
            .owning_container.unwrap(),
        pre_self_.container_map_4k@[
            pre_self_.page_array@[page_ptr2page_index(target_ptr) as int]
                .owning_container.unwrap()
        ].remove(target_ptr),
    ));
assert(post1_self_.container_map_4k@ =~= post2_self_.container_map_4k@);
